CREATE TABLE IF NOT EXISTS "users" (
	"id" INT NOT NULL,
	"email" VARCHAR NOT NULL UNIQUE,
	PRIMARY KEY("id")
);

CREATE TABLE IF NOT EXISTS "posts" (
	"id" INT NOT NULL,
	"user_id" INT NOT NULL,
	PRIMARY KEY("id"),
	FOREIGN KEY ("user_id") REFERENCES "users"("id")
	ON UPDATE CASCADE ON DELETE CASCADE
);
